INSERT INTO "public"."shows" ("created_at", "title", "description", "genre", "status", "updated_at", "id", "slug", "tmdb_id", "trakt_slug", "short_title", "release_window", "header_image", "main_color") VALUES
	('2026-03-26 16:14:17.946248+00', 'Legends of Speed', 'With personal interviews, Legends of Speed not only describes dramatic happenings on the race tracks, but also puts a spotlight on the fears, and the courage of the drivers and their relatives. All of them deal differently with the extreme sport of "Formula One" racing, but they all have one thing in common and that is the will to win.', 'Reality', 'active', '2026-03-26 16:14:18.094+00', 'efb1007c-e322-47b1-a4af-9c8e9b15c650', 'legends-of-speed-2015', '138497', 'legends-of-speed', NULL, NULL, NULL, NULL),
	('2026-03-26 16:14:18.246352+00', 'Forsthaus Rampensau Germany', '', 'Reality', 'active', '2026-03-26 16:14:18.398+00', '4014faba-1573-49b8-a4ec-fa51494d3312', 'forsthaus-rampensau-germany-2023', '240204', 'forsthaus-rampensau-germany', NULL, NULL, NULL, NULL),
	('2026-03-26 16:14:18.539131+00', 'Most Wanted – Wer entkommt?', '', 'Reality', 'active', '2026-03-26 16:14:18.7+00', 'ca52e699-1595-488a-8476-5f7eda0991c6', 'most-wanted-wer-entkommt-2025', '290303', 'most-wanted-wer-entkommt', NULL, NULL, NULL, NULL),
	('2026-03-26 16:11:44.377225+00', 'Let''s Dance', 'German version of Dancing with the Stars, the reality competition in which celebrities perform choreographed dance routines which are judged by a panel of renowned ballroom experts and voted on by viewers.', 'Reality', 'active', '2026-03-26 16:14:15.59+00', '84c71c9a-df91-4e2f-9bab-c6b68be8ccb3', 'let-s-dance-2006', '22021', 'let-s-dance-2006', NULL, NULL, NULL, NULL),
	('2026-03-26 16:11:44.829881+00', 'Homicide Unit Istanbul', 'Istanbul police commissioner Mehmet Özakin is in charge of serious crime, mainly murder investigations, mostly in the Turkish metropolis. A very modern Turk, he uses up to date Western methods, without prejudice, assisted by bachelor Mustafa Tombul. Even his private life is progressive, his wife Sevim being on the former imperial capital''s university staff.', 'Reality', 'active', '2026-03-26 16:14:15.84+00', '7fcf6d48-9f1d-4c48-8218-313ab78ba5dd', 'homicide-unit-istanbul-2008', '41015', 'homicide-unit-istanbul', NULL, NULL, NULL, NULL),
	('2026-03-26 16:14:18.831029+00', 'Berlin - Tag & Nacht', 'A german reality-TV soap opera with various changing protagonists, mainly young people and bachelors, trying to live their lifes in the giant metropole of Berlin.', 'Reality', 'active', '2026-03-26 16:14:19.017+00', 'c6a06c89-5c01-4a6f-9292-c4b9ee1f0f43', 'berlin-tag-nacht-2011', '45885', 'berlin-day-night', NULL, NULL, NULL, NULL),
	('2026-03-26 16:11:45.046549+00', 'The Race', 'In THE RACE, five creators compete against each other in a race. They have no money, no smartphone and are limited to the bare necessities for sleeping. The participants only find out exactly where they are going at the start. What doesn''t change: Whoever makes it to the finish line first has won THE RACE!', 'Reality', 'active', '2026-03-26 16:14:16.069+00', '63c95b91-20f3-4464-b2c0-2cd31cfec76b', 'the-race-2024', '257963', 'the-race-2024', NULL, NULL, NULL, NULL),
