INSERT INTO "show_management"."shows" ("created_at", "title", "description", "genre", "status", "updated_at", "id", "slug") VALUES
	('2025-03-24 19:52:44.031723+00', 'The 50', '„The 50“ auf Amazon Prime ist eine Reality-Show, in der 50 Kandidaten in spannenden Challenges gegeneinander antreten – Strategie, Teamgeist und Nervenstärke entscheiden über den Sieg!', NULL, '', NULL, 'ba5d6e24-2a72-4de0-aef3-eb19071fe268', 'the-50'),
	('2025-03-24 20:13:52.165065+00', 'Promis unter Palmen', 'Ab dem 17. Februar läuft die dritte und lang ersehnte Staffel von „Promis unter Palmen“ jeden Montag um 20:15 Uhr auf Sat. 1 und auf Joyn.', NULL, NULL, NULL, '78d4f943-395b-4a0b-a7fd-1353ee0e4f25', 'promis-unter-palmen'),
	('2025-03-24 20:22:41.692227+00', 'Couple Challenge', 'Nach einer dreijährigen Pause geht es dieses Jahr mit der 4. Staffel weiter. Neue Folgen erscheinen jeden Mittwoch um 20:15 Uhr bei RTLZWEI und immer eine Woche früher auf RTL+. Die Paare müssen in Spielen beweisen, wer das beste Team darstellt.', NULL, NULL, NULL, '27ba6bf0-1f5c-42a6-8ba6-54e3f0fed542', 'couple-challenge'),
	('2025-03-24 20:28:02.876259+00', 'Temptation Island', 'Neue Paare stellen ihre Liebe auf die ultimative Probe, während flirtwillige Singles nur darauf warten, sie in Versuchung zu führen. Knisternde Nächte, emotionale Achterbahnfahrten und explosive Enthüllungen sind garantiert! Wer bleibt seinem Partner treu – und wer fällt der Versuchung zum Opfer? Ab dem 20. März auf RTL+.', NULL, NULL, NULL, '81ff2155-9d3b-43fd-a800-99977b2f11d4', 'temptation-island'),
	('2025-03-24 20:38:39.710524+00', 'Das Sommerhaus der Normalos', 'Bei "Das Sommerhaus der Normalos" kämpfen acht Paare ohne VIP-Status um 25.000 Euro. Sie müssen schrägen Paar-Spiele und hitzige Nominierungen meistern, während ihre Beziehungen auf die Probe gestellt werden.', NULL, NULL, NULL, '4dcf95a7-b1bf-4d3e-971b-1af0334b3293', 'das-sommerhaus-der-normalos'),
	('2025-03-24 20:45:03.067453+00', 'Are You The One?', '21 Singles begeben sich auf die Suche nach ihrem Perfect Match, in der Hoffnung, am Ende 200.000 Euro mit nach Hause zu nehmen. Denn nur wenn in der 10. Matching Night alle zehn Lichter angehen, gewinnt die Gruppe den Jackpot.', NULL, NULL, NULL, '66795774-bab8-41f3-a31b-176adcff4fde', 'are-you-the-one-'),
	('2025-03-24 20:57:49.781047+00', 'Germany''s Next Topmodel ', '20 Jahre glamouröse Fotoshootings, 20 Jahre herausfordernde Catwalks und Challenges, 20 Jahre "Germany''s Next Topmodel - by Heidi Klum"! Mit über 300 Folgen, mehr als 3000 Kandidatinnen und Kandidaten und Millionen begeisterter Zuschauer:innen hat die Show Geschichte geschrieben. Grund genug die Jubiläumsstaffel gebührend zu feiern. Wie? Doppelt natürlich!', NULL, NULL, NULL, 'a6cba8bb-6783-45e3-81fe-82e32c7ca0df', 'germany-s-next-topmodel-'),
	('2025-03-24 21:15:29.600785+00', 'EX on the Beach', 'Singles erleben paradiesische Dates, bis ihre Ex-Partner:innen plötzlich auf der Bildfläche erscheinen. Alte Konflikte flammen wieder auf und neue Beziehungen werden auf die Probe gestellt. Drama, Romantik und überraschende Wendungen sind also garantiert.', NULL, NULL, NULL, '8f1291aa-bd64-4a0e-9b9a-320166a1e63e', 'ex-on-the-beach');
